{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOoy8fkVwnl6r6Dwo0ntEGZ"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"S39E4tlb7YB-"},"outputs":[],"source":["# -------------------------------\n","# ADDING ELEMENTS\n","# -------------------------------\n","\n","# 1. append()\n","nums = []\n","nums.append(10)\n","nums.append(20)\n","nums.append(30)\n","nums.append(40)\n","nums.append(50)\n","print(\"After append:\", nums)\n","\n","# 2. insert()\n","nums.insert(2, 99)\n","print(\"After insert at index 2:\", nums)\n","\n","# 3. extend()\n","extra = [60, 70, 80]\n","nums.extend(extra)\n","print(\"After extend:\", nums)\n","\n","# 4. append vs extend\n","list_a = [1, 2, 3]\n","list_b = [4, 5]\n","\n","list_a.append(list_b)\n","print(\"\\nAppend result:\", list_a)\n","\n","list_c = [1, 2, 3]\n","list_c.extend(list_b)\n","print(\"Extend result:\", list_c)\n","\n","\n","# -------------------------------\n","# REMOVING ELEMENTS\n","# -------------------------------\n","\n","data = [10, 20, 30, 40, 50]\n","\n","# remove()\n","data.remove(30)\n","print(\"\\nAfter remove:\", data)\n","\n","# pop() last element\n","last = data.pop()\n","print(\"Popped last element:\", last)\n","\n","# pop() at index 3\n","removed_index = data.pop(1)\n","print(\"Popped index 1:\", removed_index)\n","print(\"After pop index:\", data)\n","\n","# clear()\n","temp = [1, 2, 3]\n","temp.clear()\n","print(\"After clear:\", temp)\n","\n","\n","# -------------------------------\n","# SEARCHING & COUNTING\n","# -------------------------------\n","\n","nums2 = [1, 2, 2, 3, 2, 4]\n","\n","print(\"\\nCount of 2:\", nums2.count(2))\n","print(\"Index of 3:\", nums2.index(3))\n","\n","# index() not found case\n","try:\n","    print(nums2.index(99))\n","except ValueError:\n","    print(\"Value 99 not found in list\")\n","\n","\n","# -------------------------------\n","# ORDERING METHODS\n","# -------------------------------\n","\n","arr = [5, 2, 9, 1, 7]\n","\n","arr.sort()\n","print(\"\\nAscending sort:\", arr)\n","\n","arr.sort(reverse=True)\n","print(\"Descending sort:\", arr)\n","\n","arr.reverse()\n","print(\"Reversed list:\", arr)\n","\n","# copy()\n","original = [10, 20, 30]\n","copied = original.copy()\n","copied.append(40)\n","\n","print(\"\\nOriginal:\", original)\n","print(\"Copied modified:\", copied)\n","\n","\n","# -------------------------------\n","# PRACTICE QUESTIONS\n","# -------------------------------\n","\n","# Remove duplicates using methods only\n","dup_list = [1, 2, 2, 3, 3, 4]\n","unique_list = list(set(dup_list))\n","print(\"\\nWithout duplicates:\", unique_list)\n","\n","# Combine two lists\n","l1 = [1, 2, 3]\n","l2 = [4, 5, 6]\n","l1.extend(l2)\n","print(\"Combined list:\", l1)\n","\n","# Replace element at index 2\n","l1[2] = 99\n","print(\"After replacing index 2:\", l1)\n","\n","# Count largest element occurrences\n","nums3 = [5, 9, 9, 2, 9, 1]\n","largest = max(nums3)\n","print(\"Largest:\", largest)\n","print(\"Count of largest:\", nums3.count(largest))\n","\n","# Sort words alphabetically\n","words = [\"banana\", \"apple\", \"mango\", \"cherry\"]\n","words.sort()\n","print(\"\\nSorted words:\", words)"]}]}